class Playground {
    async run(inputs) {
        const nums = JSON.parse(inputs[0]);
        const result = [];
        this.slots.input_array.init(nums);
        this.slots.callstack.init();
        this.slots.recursion_tree.init();

        await this.backtrack(nums, [], result);

        this.log('Permutation generation complete.');
        this.slots.result_list.init(result);
        return result;
    }

    async backtrack(nums, currentPermutation, result) {
        const nodeId = Math.random().toString(36).substring(7);
        this.slots.recursion_tree.enterNode(nodeId, `Permute(${currentPermutation.length === nums.length ? 'Base Case' : 'Recursive Step'})`);
        this.slots.callstack.pushFrame('backtrack', { nums: nums.join(','), currentPermutation: currentPermutation.join(',') });

        if (currentPermutation.length === nums.length) {
            this.log('Base case reached: A complete permutation is found.');
            result.push([...currentPermutation]);
            this.slots.recursion_tree.exitNode('#00f5a0'); // Success color
            this.slots.callstack.popFrame('return');
            await this.await();
            return;
        }

        for (let i = 0; i < nums.length; i++) {
            if (currentPermutation.includes(nums[i])) {
                continue; // Skip if the number is already in the current permutation
            }

            this.log(`Trying to add ${nums[i]} to the current permutation.`);
            this.slots.input_array.highlight(i, '#ffb703'); // Highlight current number being considered
            currentPermutation.push(nums[i]);
            this.slots.callstack.updateLocal('currentPermutation', currentPermutation.join(','));
            await this.await();

            await this.backtrack(nums, currentPermutation, result);

            this.log(`Backtracking: Removing ${nums[i]} from the current permutation.`);
            currentPermutation.pop();
            this.slots.callstack.updateLocal('currentPermutation', currentPermutation.join(','));
            this.slots.input_array.highlight(i, '#00e0ff'); // Reset highlight
            await this.await();
        }

        this.slots.recursion_tree.exitNode('#ff0000'); // Failure/Backtrack color
        this.slots.callstack.popFrame('return');
    }
}
